function createBaseVersion(): Version {
  return { Major: 0, Minor: 0, Patch: 0, Commit: "", Dirty: false, CompiledAt: "0", OS: "", Arch: "" };
}

export const Version: MessageFns<Version> = {
  encode(message: Version, writer: BinaryWriter = new BinaryWriter()): BinaryWriter {
    if (message.Major !== 0) {
      writer.uint32(8).int32(message.Major);
    }
    if (message.Minor !== 0) {
      writer.uint32(16).int32(message.Minor);
    }
    if (message.Patch !== 0) {
      writer.uint32(24).int32(message.Patch);
    }
    if (message.Commit !== "") {
      writer.uint32(34).string(message.Commit);
    }
    if (message.Dirty !== false) {
      writer.uint32(40).bool(message.Dirty);
    }
    if (message.CompiledAt !== "0") {
      writer.uint32(48).int64(message.CompiledAt);
    }
    if (message.OS !== "") {
      writer.uint32(58).string(message.OS);
    }
    if (message.Arch !== "") {
      writer.uint32(66).string(message.Arch);
    }
    return writer;
  },

  decode(input: BinaryReader | Uint8Array, length?: number): Version {
    const reader = input instanceof BinaryReader ? input : new BinaryReader(input);
    const end = length === undefined ? reader.len : reader.pos + length;
    const message = createBaseVersion();
    while (reader.pos < end) {
      const tag = reader.uint32();
      switch (tag >>> 3) {
        case 1: {
          if (tag !== 8) {
            break;
          }

          message.Major = reader.int32();
          continue;
        }
        case 2: {
          if (tag !== 16) {
            break;
          }

          message.Minor = reader.int32();
          continue;
        }
        case 3: {
          if (tag !== 24) {
            break;
          }

          message.Patch = reader.int32();
          continue;
        }
        case 4: {
          if (tag !== 34) {
            break;
          }

          message.Commit = reader.string();
          continue;
        }
        case 5: {
          if (tag !== 40) {
            break;
          }

          message.Dirty = reader.bool();
          continue;
        }
        case 6: {
          if (tag !== 48) {
            break;
          }

          message.CompiledAt = reader.int64().toString();
          continue;
        }
        case 7: {
          if (tag !== 58) {
            break;
          }

          message.OS = reader.string();
          continue;
        }
        case 8: {
          if (tag !== 66) {
            break;
          }

          message.Arch = reader.string();
          continue;
        }
      }
      if ((tag & 7) === 4 || tag === 0) {
        break;
      }
      reader.skip(tag & 7);
    }
    return message;
  },

  fromJSON(object: any): Version {
    return {
      Major: isSet(object.Major) ? globalThis.Number(object.Major) : 0,
      Minor: isSet(object.Minor) ? globalThis.Number(object.Minor) : 0,
      Patch: isSet(object.Patch) ? globalThis.Number(object.Patch) : 0,
      Commit: isSet(object.Commit) ? globalThis.String(object.Commit) : "",
      Dirty: isSet(object.Dirty) ? globalThis.Boolean(object.Dirty) : false,
      CompiledAt: isSet(object.CompiledAt) ? globalThis.String(object.CompiledAt) : "0",
      OS: isSet(object.OS) ? globalThis.String(object.OS) : "",
      Arch: isSet(object.Arch) ? globalThis.String(object.Arch) : "",
    };
  },

  toJSON(message: Version): unknown {
    const obj: any = {};
    if (message.Major !== 0) {
      obj.Major = Math.round(message.Major);
    }
    if (message.Minor !== 0) {
      obj.Minor = Math.round(message.Minor);
    }
    if (message.Patch !== 0) {
      obj.Patch = Math.round(message.Patch);
    }
    if (message.Commit !== "") {
      obj.Commit = message.Commit;
    }
    if (message.Dirty !== false) {
      obj.Dirty = message.Dirty;
    }
    if (message.CompiledAt !== "0") {
      obj.CompiledAt = message.CompiledAt;
    }
    if (message.OS !== "") {
      obj.OS = message.OS;
    }
    if (message.Arch !== "") {
      obj.Arch = message.Arch;
    }
    return obj;
  },

  create(base?: DeepPartial<Version>): Version {
    return Version.fromPartial(base ?? {});
  },
  fromPartial(object: DeepPartial<Version>): Version {
    const message = createBaseVersion();
    message.Major = object.Major ?? 0;
    message.Minor = object.Minor ?? 0;
    message.Patch = object.Patch ?? 0;
    message.Commit = object.Commit ?? "";
    message.Dirty = object.Dirty ?? false;
    message.CompiledAt = object.CompiledAt ?? "0";
    message.OS = object.OS ?? "";
    message.Arch = object.Arch ?? "";
    return message;
  },
};

